1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block alive (still life)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	    expect(result).toHaveLength(4);
17	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]] as Cell[]));
18	  });
19	  it("should oscillate a vertical blinker to horizontal", () => {
20	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
21	    expect(result).toHaveLength(3);
22	    expect(result).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]] as Cell[]));
23	  });
24	  it("should create a new cell from reproduction (dead cell with exactly 3 neighbors)", () => {
25	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
26	    expect(result).toEqual(expect.arrayContaining([[1, 1]] as Cell[]));
27	  });
28	  it("should kill a live cell with 4 neighbors (overpopulation)", () => {
29	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]]);
30	    expect(result).not.toContainEqual([1, 1]);
31	  });
32	  it.todo("should support negative coordinates");
33	});
34

1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	export const nextGeneration = (cells: Cell[]): Cell[] => {
12	  const liveSet = new Set(cells.map(cellKey));
13	
14	  const neighbors = new Map<string, { cell: Cell; count: number }>();
15	  for (const [x, y] of cells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const cell: Cell = [x + dx, y + dy];
18	      const k = cellKey(cell);
19	      const entry = neighbors.get(k);
20	      if (entry) entry.count++;
21	      else neighbors.set(k, { cell, count: 1 });
22	    }
23	  }
24	
25	  const isAliveNextGen = (k: string, count: number): boolean =>
26	    count === 3 || (count === 2 && liveSet.has(k));
27	
28	  const nextCells: Cell[] = [];
29	  for (const [k, { cell, count }] of neighbors) {
30	    if (isAliveNextGen(k, count)) nextCells.push(cell);
31	  }
32	  return nextCells;
33	};
